module top_module(/*AUTOARG*/
   // Outputs
   q,
   // Inputs
   clk, rst_l, d
   );input clk;
   input rst_l;
   input [3:0] d;
   output reg [3:0] q;

     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk, negedge rst_l or posedge dbg_halt) begin
      if (~rst_l) begin
         q <= 4'b0000;
      end else begin
         q <= d;
      end
   end

endmodule
